{"db_name":"stocktrade_database","query":"SELECT Symbol, days FROM (
  SELECT 'AGMH' AS Symbol, COUNT(*) AS days FROM "AGMH" WHERE Date >= '2019-01-01' AND Date < '2020-01-01' AND Low > 0 AND (High - Low)/Low > 0.2
  UNION ALL
  SELECT 'APEX' AS Symbol, COUNT(*) AS days FROM "APEX" WHERE Date >= '2019-01-01' AND Date < '2020-01-01' AND Low > 0 AND (High - Low)/Low > 0.2
) x ORDER BY days DESC, Symbol ASC LIMIT 5;"}

